// Mock status bar render logic
pub struct StatusBarViewModel {
    pub current_model: Option<String>,
    pub session_token_usage: TokenUsage,
}

// Current behavior: nothing renders when current_model is None
fn build_center_line(vm: &StatusBarViewModel) -> String {
    if let Some(model) = &vm.current_model {
        format!("{} · {} tokens", model, vm.session_token_usage.total_tokens)
    } else {
        // BUG: Empty string when no model - user has no warning!
        String::new()
    }
}
